  8→/// <summary>
  9→/// URDF 기반 TM12 로봇 6축 관절 체인.
 10→/// ModelVisual3D 중첩으로 kinematic chain 구성.
 11→/// </summary>
 12→public class RobotModel
 13→{
 14→    // 각 관절의 AxisAngleRotation3D (Angle 값만 변경하면 됨)
 15→    private readonly AxisAngleRotation3D[] _jointRotations = new AxisAngleRotation3D[6];
 16→
 17→
 18→    // 루트 ModelVisual3D (HelixViewport3D에 추가)
 19→    public ModelVisual3D RootVisual { get; }
 20→
 21→    // URDF 단위가 미터이므로 mm 변환 스케일
 22→    private const double SCALE = 1000.0;
 23→
 24→    public RobotModel()
 25→    {
 26→        // 관절 회전 초기화
 27→        for (int i = 0; i < 6; i++)
 28→            _jointRotations[i] = new AxisAngleRotation3D(new Vector3D(0, 0, 1), 0);
 29→
 30→        RootVisual = BuildKinematicChain();
 31→    }
 32→
 33→    // TM Robot 보고 각도 → URDF 각도 오프셋 (J2: +90°)
 34→    private static readonly double[] JointOffsets = [0, -90, 0, 0, 0, 0];
 35→
 36→    /// <summary>
 37→    /// 모든 관절 각도 설정 (도 단위, J1~J6)
 38→    /// </summary>
 39→    public void SetAllJointAngles(double[] angles)
 40→    {
 41→        for (int i = 0; i < Math.Min(angles.Length, 6); i++)
 42→            _jointRotations[i].Angle = angles[i] + JointOffsets[i];
 43→    }
 44→
 45→    /// <summary>
 46→    /// 개별 관절 각도 설정 (0-based index, 도 단위)
 47→    /// </summary>
 48→    public void SetJointAngle(int index, double angleDeg)
 49→    {
 50→        if (index >= 0 && index < 6)
 51→            _jointRotations[index].Angle = angleDeg;
 52→    }
