207→    /// <summary>
208→    /// STL 파일 로딩 — mm 단위 (스케일 변환 없음)
209→    /// </summary>
210→    private static Model3DGroup? LoadStlMm(string filePath)
211→    {
212→        if (!File.Exists(filePath))
213→        {
214→            System.Diagnostics.Debug.WriteLine($"[RobotModel] STL 파일 없음: {filePath}");
215→            return null;
216→        }
217→        try
218→        {
219→            var reader = new StLReader();
220→            return reader.Read(filePath);
221→        }
222→        catch (Exception ex)
223→        {
224→            System.Diagnostics.Debug.WriteLine($"[RobotModel] STL 로드 예외: {filePath} - {ex.Message}");
225→            return null;
226→        }
227→    }
228→
229→    /// <summary>
230→    /// STL 파일 로딩 (HelixToolkit StLReader 사용)
231→    /// 실패 시 Debug 출력 + Trace 로그
232→    /// </summary>
233→    private static Model3DGroup? LoadStl(string filePath)
234→    {
235→        if (!File.Exists(filePath))
236→        {
237→            var msg = $"[RobotModel] STL 파일 없음: {filePath}";
238→            System.Diagnostics.Debug.WriteLine(msg);
239→            System.Diagnostics.Trace.TraceWarning(msg);
240→            return null;
241→        }
242→
243→        try
244→        {
245→            var reader = new StLReader();
246→            var model = reader.Read(filePath);
247→            if (model == null)
248→            {
249→                var msg = $"[RobotModel] STL 로드 실패 (null 반환): {filePath}";
250→                System.Diagnostics.Debug.WriteLine(msg);
251→                System.Diagnostics.Trace.TraceWarning(msg);
252→                return null;
253→            }
254→            // URDF STL은 미터 단위 → mm 변환
255→            model.Transform = new ScaleTransform3D(SCALE, SCALE, SCALE);
256→            return model;
257→        }
258→        catch (Exception ex)
259→        {
260→            var msg = $"[RobotModel] STL 로드 예외: {filePath} - {ex.Message}";
261→            System.Diagnostics.Debug.WriteLine(msg);
262→            System.Diagnostics.Trace.TraceError(msg);
263→            return null;
264→        }
265→    }
