267→    /// <summary>
268→    /// 메시 Visual 생성
269→    /// </summary>
270→    private static ModelVisual3D CreateMeshVisual(Model3DGroup meshGroup, Material material)
271→    {
272→        // 모든 GeometryModel3D에 material 적용
273→        foreach (var model in meshGroup.Children)
274→        {
275→            if (model is GeometryModel3D geoModel)
276→            {
277→                geoModel.Material = material;
278→                geoModel.BackMaterial = material;
279→            }
280→        }
281→
282→        return new ModelVisual3D { Content = meshGroup };
283→    }
