 52→    /// <summary>
 53→    /// 로봇 모델에 맞춰 카메라 설정 (베이스가 화면 하단에 오도록)
 54→    /// </summary>
 55→    private void SetDefaultCamera()
 56→    {
 57→        var cam = Viewport3D.Camera as PerspectiveCamera;
 58→        if (cam == null) return;
 59→
 60→        var target = new Point3D(0, 0, 400);
 61→        var cameraPos = new Point3D(2200, -2200, 1400);
 62→
 63→        cam.Position = cameraPos;
 64→        cam.LookDirection = target - cameraPos;
 65→        cam.UpDirection = new Vector3D(0, 0, 1);
 66→        cam.FieldOfView = 45;
 67→
 68→        Viewport3D.CameraController.CameraTarget = target;
 69→    }
