 93→    /// <summary>
 94→    /// TCP 리소스 정리 (이벤트 발사 없음)
 95→    /// </summary>
 96→    private void CleanupResources()
 97→    {
 98→        _isConnected = false;
 99→        try
100→        {
101→            _cts?.Cancel();
102→            _stream?.Close();
103→            _tcp?.Close();
104→        }
105→        catch { }
106→        finally
107→        {
108→            _stream = null;
109→            _tcp = null;
110→            _cts = null;
111→            _receiveTask = null;
112→            _recvBuffer.Clear();
113→        }
114→    }
